import React, { Component } from "react";
import { AppBar, Toolbar, IconButton, Typography, Drawer, List, ListItem, ListItemText, Box } from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";
import { withTheme } from "@mui/styles";
import withWidthHOC from "../../utils/withWidthHOC"; // Your custom HOC for width

const navItems = ["About", "Skills", "Experience", "Projects", "Education", "Contact"];

class Layout extends Component {
  constructor(props) {
    super(props);
    this.state = {
      sidebarOpen: false,
      selectedContent: "Welcome to My Portfolio"
    };
  }

  toggleSidebar = (open) => {
    this.setState({ sidebarOpen: open });
  };

  handleNavClick = (text) => {
    this.setState({ selectedContent: text, sidebarOpen: false });
  };

  render() {
    const { children, theme, width } = this.props;
    const { sidebarOpen, selectedContent } = this.state;
    const isMobile = width === "xs" || width === "sm"; // Mobile check

    return (
      <>
        <AppBar position="static">
          <Toolbar>
            {isMobile && (
              <IconButton
                edge="start"
                color="inherit"
                aria-label="menu"
                onClick={() => this.toggleSidebar(true)}
              >
                <MenuIcon />
              </IconButton>
            )}
            <Typography variant="h6" sx={{ flexGrow: 1 }}>
              My Portfolio
            </Typography>

            {/* Web view - Display menu on larger screens */}
            <Box
              sx={{
                display: { xs: "none", md: "flex" }, // Show on medium screens and above
                marginLeft: "auto" // Align to the right
              }}
            >
              {navItems.map((item) => (
                <Typography
                  key={item}
                  sx={{ margin: "0 10px", cursor: "pointer" }}
                  onClick={() => this.handleNavClick(item)}
                >
                  {item}
                </Typography>
              ))}
            </Box>
          </Toolbar>
        </AppBar>

        {/* Sidebar (Mobile View) */}
        <Drawer anchor="left" open={sidebarOpen} onClose={() => this.toggleSidebar(false)}>
          <List>
            {navItems.map((text) => (
              <ListItem button key={text} onClick={() => this.handleNavClick(text)}>
                <ListItemText primary={text} />
              </ListItem>
            ))}
          </List>
        </Drawer>

        {/* Main content area */}
        <Box sx={{ padding: 2 }}>
          {children || <Typography>{selectedContent}</Typography>}
        </Box>
      </>
    );
  }
}

// Wrap the component with the custom HOC for width
export default withTheme(withWidthHOC(Layout));
